float *CUDAFindNearestNeighbors(
    int numRecords,
    std::vector<LatLong> &locations,
    float lat,
    float lng,
    int timing) {

    LatLong *d_locations;
    float *d_distances;
    cudaError_t err;

    // Allocate device memory
    err = cudaMalloc((void**)&d_locations, sizeof(LatLong) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_locations failed: %s\n", cudaGetErrorString(err));
        exit(1);
    }

    err = cudaMalloc((void**)&d_distances, sizeof(float) * numRecords);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMalloc d_distances failed: %s\n", cudaGetErrorString(err));
        exit(1);
    }

    // Copy data to device
    err = cudaMemcpy(d_locations, &locations[0], sizeof(LatLong) * numRecords, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_locations failed: %s\n", cudaGetErrorString(err));
        exit(1);
    }

    // Setup kernel arguments via direct call
    int blockSize = 64;
    int numBlocks = (numRecords + blockSize - 1) / blockSize;

    // Launch kernel
    NearestNeighbor<<<numBlocks, blockSize>>>(d_locations, d_distances, numRecords, lat, lng);

    err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaDeviceSynchronize failed: %s\n", cudaGetErrorString(err));
        exit(1);
    }

    // Allocate host memory for results
    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "malloc failed for distances\n");
        exit(1);
    }

    // Copy results back to host
    err = cudaMemcpy(distances, d_distances, sizeof(float) * numRecords, cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "cudaMemcpy d_distances failed: %s\n", cudaGetErrorString(err));
        exit(1);
    }

    // Cleanup device memory
    cudaFree(d_locations);
    cudaFree(d_distances);

    return distances;
}

int main(int argc, char *argv[]) {
    std::vector<Record> records;
    float *recordDistances;
    std::vector<LatLong> locations;
    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    int numRecords = loadData(filename, records, locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords) resultsCount = numRecords;

    // Initialize CUDA (implicit in first call, but good practice to check)
    cudaSetDevice(0);

    recordDistances = CUDAFindNearestNeighbors(numRecords, locations, lat, lng, timing);

    findLowest(records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records[i].recString, records[i].distance);
        }

    free(recordDistances);
    return 0;
}
